local FEEDBACK_COOLDOWN, lastFeedback = 20, 0
local ERRMAP = {
    empty = "A mensagem está vazia.", no_links = "Links não são permitidos.",
    too_long = "A mensagem é muito longa (máximo de 500 caracteres).", rate_limited = "Você atingiu o limite de 3 mensagens. Tente novamente mais tarde.",
    busy = "O servidor está ocupado. Tente novamente.", banned = "Você não tem permissão para enviar feedback.",
    discord_error = "Falha no envio. Tente novamente.", network = "Erro de rede.",
    no_request = "Seu executor não consegue enviar requisições.", bad_response = "O servidor retornou uma resposta inesperada.",
    unreachable = "Seu executor não consegue acessar o servidor (erro de TLS). Tente um executor diferente.",
}
local FG = Tabs.Suggest:AddLeftGroupbox("Sugestões / Ajuda", "message-square")
FG:AddDropdown("FeedbackType", {Text = "Tipo", Values = {"Suggestion", "Bug", "Help"}, Default = "Suggestion", Callback = function() end})
FG:AddInput("FeedbackMsg", {Default = "", Numeric = false, Finished = false, ClearTextOnFocus = false, Text = "Mensagem", Placeholder = "Digite sua mensagem (máximo de 500 caracteres, sem links)"})
local fbStatus = FG:AddLabel("", true)
FG:AddButton({
    Text = "📨 Send",
    Func = function()
        local now = tick()
        if now - lastFeedback < FEEDBACK_COOLDOWN then
            safeSet(fbStatus, string.format("Aguarde %d segundos antes de enviar novamente.", math.ceil(FEEDBACK_COOLDOWN - (now - lastFeedback))))
            return
        end
        local ftype = tostring((Options.FeedbackType and Options.FeedbackType.Value) or "Suggestion"):lower()
        local msg   = M.trim((Options.FeedbackMsg and Options.FeedbackMsg.Value) or "")
        if msg == "" then safeSet(fbStatus, "A mensagem está vazia."); return end
        if #msg > 500 then safeSet(fbStatus, "A mensagem é muito longa (máximo de 500 caracteres)."); return end
        local low = msg:lower()
        if low:find("http", 1, true) or low:find("discord.gg", 1, true) or low:find("www.", 1, true) or low:find(".gg/", 1, true) then
            safeSet(fbStatus, "Links não são permitidos."); return
        end
        safeSet(fbStatus, "Enviando...")
        task.spawn(function()
            local sok, err = M.sendFeedback(ftype, msg, (preCheck and preCheck.session_token) or "")
            if sok then
                lastFeedback = tick()
                safeSet(fbStatus, "✅ Enviado. Obrigado!")
                pcall(function() Options.FeedbackMsg:SetValue("") end)
                Library:Notify({Title = "COMBOWICK", Description = "Seu feedback foi enviado. Obrigado!", Time = 3})
            else
                safeSet(fbStatus, ERRMAP[err] or ("Falha ao enviar: " .. tostring(err)))
            end
        end)
    end,
})
FG:AddLabel("Máximo de 3 mensagens por hora. Sem links ou menções.", true)

