task.spawn(function()
    safeSet(statusLabel, "Autenticando...")

    local result = M.withRetry(M.checkSession, M.hwid)

    if result == nil then
        safeSet(statusLabel, "Status: Falhou")
        Library:Notify({Title="COMBOWICK", Description="A verificação da sessão falhou.", Time=5})

    elseif result.status == "allowed" or result.status == "session_active" then
        if result.disabled then
            safeSet(statusLabel, "⛔ Jogo Desativado")
            safeSet(hintLabel, "A versão gratuita não está disponível aqui. Obtenha uma chave.")
            Library:Notify({Title="COMBOWICK", Description="A versão gratuita está desativada para este jogo. Use uma chave.", Time=6})
            return
        end
        local token = result.session_token
        if type(token) ~= "string" or #token < 20 then
            safeSet(statusLabel, "Status: Falhou")
        else
            safeSet(statusLabel, "Status: Autenticado")
            Library:Notify({Title="COMBOWICK", Description="Você está autenticado.", Time=3})
            _G.COMBOWICK_FREE   = true
            _G.COMBOWICK_ACTIVE = true
            local remaining = tonumber(result.remaining) or 0
            task.spawn(function()
                while remaining > 0 do
                    local fmt = M.formatTime(remaining)
                    safeSet(timerLabel, string.format("Tempo restante: %s", fmt))
                    safeSet(lSession, string.format("Tempo de sessão: %s", fmt))
                    task.wait(1); remaining = remaining - 1
                end
                safeSet(timerLabel, "A sessão expirou.")
                safeSet(lSession, "Tempo de sessão: expirado")
                _G.COMBOWICK_ACTIVE = false
                pcall(function() Library:Unload() end)
                task.wait(0.5)
                M.reloadExist()
            end)
            local scriptUrl = M.getScriptForGame(token)
            if M.loadFreeScript(scriptUrl, token) then task.wait(2); pcall(function() Library:Unload() end) end
        end

    elseif result.status == "cooldown" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Em Espera")
        safeSet(hintLabel, "Obtenha uma chave de 11 horas ou aguarde o fim da espera.")
        Library:Notify({Title="COMBOWICK", Description="Você está em espera. Obtenha uma chave para pular a espera.", Time=6})
        task.spawn(function()
            while remaining > 0 do
                local fmt = M.formatTime(remaining)
                safeSet(timerLabel, string.format("Espera: %s", fmt))
                safeSet(lCooldown, string.format("Espera: %s", fmt))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "A espera terminou.")
            safeSet(lCooldown, "Espera: concluída")
            safeSet(hintLabel, "")
            Library:Notify({Title="COMBOWICK", Description="A espera terminou. Recarregando...", Time=3})
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "throttled" then
        local remaining = tonumber(result.remaining) or 0
        safeSet(statusLabel, "Requisições em Excesso")
        safeSet(hintLabel, "Requisições em excesso. Aguarde.")
        Library:Notify({Title="COMBOWICK", Description="Requisições em excesso. Aguarde um momento.", Time=5})
        task.spawn(function()
            while remaining > 0 do
                safeSet(timerLabel, string.format("Tentar novamente em %s", M.formatTime(remaining)))
                task.wait(1); remaining = remaining - 1
            end
            safeSet(timerLabel, "Recarregando...")
            safeSet(hintLabel, "")
            pcall(function() Library:Unload() end)
            task.wait(0.5)
            M.reloadExist()
        end)

    elseif result.status == "disabled" then
        safeSet(statusLabel, "Serviço Pausado")
        safeSet(hintLabel, "O COMBOWICK está temporariamente offline.")
        Library:Notify({Title="COMBOWICK", Description="O serviço está desativado no momento. Tente novamente mais tarde.", Time=6})

    elseif result.status == "banned" then
        safeSet(statusLabel, "Banido")
        Library:Notify({Title="COMBOWICK", Description="Você está banido.", Time=5})

    elseif result.status == "game_not_allowed" then
        safeSet(statusLabel, "🚫 Jogo Não Suportado")
        safeSet(hintLabel, "Este jogo ainda não é suportado. Chaves premium ainda funcionam se houver um script disponível.")
        Library:Notify({Title="COMBOWICK", Description="Este jogo ainda não é suportado.", Time=6})

    else
        safeSet(statusLabel, "Erro")
        safeSet(hintLabel, "Não foi possível acessar o servidor. Execute o script novamente.")
        Library:Notify({Title="COMBOWICK", Description=tostring(result.message or "Ocorreu um erro desconhecido."), Time=5})
    end
end)

